parameters.functionCode:
const payload = $input.item.json.payload;
return [{
  json: {
    nombre: payload.invitee?.name || 'Cliente',
    email: payload.invitee?.email,
    fecha_sesion: payload.event?.start_time,
    fecha_formateada: new Date(payload.event?.start_time).toLocaleDateString('es-MX', {
      weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
    }),
    hora_formateada: new Date(payload.event?.start_time).toLocaleTimeString('es-MX', {
      hour: '2-digit', minute: '2-digit'
    }),
    cancel_url: payload.invitee?.cancel_url,
    reschedule_url: payload.invitee?.reschedule_url,
    timestamp_24h_antes: new Date(new Date(payload.event?.start_time).getTime() - 24*60*60*1000).toISOString(),
    timestamp_1h_antes: new Date(new Date(payload.event?.start_time).getTime() - 60*60*1000).toISOString()
  }
}];
